impl Solution { pub fn new21_game(n: i32, k: i32, max_pts: i32) -> f64 { if k == 0 || n >= k + max_pts { return 1.0; } let mut black_dp = vec![0.0; n as usize + 1]; black_dp[0] = 1.0; let mut black_win_sum = 1.0; let mut res = 0.0; for i in 1..=n as usize { black_dp[i] = black_win_sum / max_pts as f64; if i < k as usize { black_win_sum += black_dp[i]; } else { res += black_dp[i]; } if i >= max_pts as usize { black_win_sum -= black_dp[i - max_pts as usize]; } } res } }
